let observer = null;

export function initInfiniteScroll(sentinelElement, containerElement, dotNetRef) {
    dispose();

    observer = new IntersectionObserver(
        (entries) => {
            const entry = entries[0];
            if (entry.isIntersecting) {
                dotNetRef.invokeMethodAsync("OnSentinelVisible");
            }
        },
        {
            root: containerElement,
            rootMargin: "0px 0px 200px 0px",
            threshold: 0
        }
    );

    observer.observe(sentinelElement);
}

export function dispose() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

.infinite-scroll-container {
    overflow-y: auto;
    max-height: 80vh;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 3px solid #e0e0e0;
    border-top-color: #0d6efd;
    border-radius: 50%;
    animation: infinite-scroll-spin 0.8s linear infinite;
}

@keyframes infinite-scroll-spin {
    to {
        transform: rotate(360deg);
    }
}

